const res = $input.first().json;
const opps = (res.opportunities || []).filter(o => o.jobType === 'editorial');
if (opps.length === 0) { return []; } // nothing to do this run
const opp = opps[0];

const system = [
  'You are a senior carbon-market analyst writing for KarbonLens, an Indonesian carbon-market intelligence terminal.',
  'Write in clear, specific, professional English (or Bahasa Indonesia if the target query is Indonesian).',
  '',
  'HARD RULES:',
  '- You may ONLY state numeric facts that appear in the provided grounding list. Never invent prices, volumes, dates, credit counts, or statistics.',
  '- For every grounding number you use in the body, add an entry to claims with its factKey and the exact value you wrote (as a string).',
  '- Only link to paths in relatedUrls or obvious on-site sections (/projects, /prices, /regulatory, /glossary, /methodology, /news).',
  '- Do NOT use AI-tell phrases: "in the ever-evolving", "in conclusion", "it is important to note", "delve into", "navigating the", "a testament to", "game-changer", "rich tapestry". Lead with the concrete data point.',
  '- 1,500 to 8,000 characters of Markdown. Title <= 70 chars. Summary <= 320 chars. slug is lowercase kebab-case.',
  '',
  'Return ONLY JSON: { "kind", "slug", "title", "summary", "bodyMd", "claims":[{"factKey","statedValue"}], "internalLinks":[] }.'
].join('\n');

const user = [
  'Target query: ' + (opp.targetQuery || ''),
  '',
  'Brief: ' + opp.brief,
  '',
  'Grounding facts (you may ONLY cite these numbers):',
  JSON.stringify(opp.grounding, null, 2),
  '',
  'Suggested kind: ' + ((opp.hints && opp.hints.suggestedKind) || 'explainer'),
  'Related on-site URLs you may link: ' + JSON.stringify((opp.hints && opp.hints.relatedUrls) || [])
].join('\n');

const openaiBody = {
  model: 'gpt-4o',
  response_format: { type: 'json_object' },
  temperature: 0.4,
  messages: [ { role: 'system', content: system }, { role: 'user', content: user } ]
};

return [{ json: { opp, openaiBody } }];

const prev = $('Pick Top + Build Prompt').first().json;
const opp = prev.opp;
const ai = $input.first().json;
const content = ai.choices && ai.choices[0] && ai.choices[0].message ? ai.choices[0].message.content : '{}';
let artifact;
try { artifact = JSON.parse(content); } catch (e) { throw new Error('OpenAI did not return JSON: ' + String(content).slice(0, 200)); }
const usage = ai.usage || {};
const payload = {
  jobType: 'editorial',
  ref: opp.ref,
  externalId: String($execution.id),
  llmModel: prev.openaiBody.model,
  tokensIn: usage.prompt_tokens,
  tokensOut: usage.completion_tokens,
  targetQuery: opp.targetQuery,
  kind: artifact.kind || (opp.hints && opp.hints.suggestedKind) || 'explainer',
  slug: artifact.slug,
  title: artifact.title,
  summary: artifact.summary,
  bodyMd: artifact.bodyMd,
  claims: artifact.claims || [],
  internalLinks: artifact.internalLinks || [],
  grounding: opp.grounding
};
return [{ json: payload }];
